import React, { useRef, useEffect } from 'react';
import { QRCodeCanvas } from 'qrcode.react';
import './QRCodeModal.css';

/**
 * QRCodeModal — Feature 8
 * Shows QR code for a campaign URL, allows download as PNG and WhatsApp share.
 * Props:
 *   campaignUrl: string
 *   campaignTitle: string
 *   onClose: () => void
 *   onShare: () => void  (callback after WhatsApp share to track in parent)
 */
const QRCodeModal = ({ campaignUrl, campaignTitle, onClose, onShare }) => {
  const canvasRef = useRef(null);

  // Close on Escape key
  useEffect(() => {
    const handleKeyDown = (e) => { if (e.key === 'Escape') onClose(); };
    document.addEventListener('keydown', handleKeyDown);
    return () => document.removeEventListener('keydown', handleKeyDown);
  }, [onClose]);

  const handleDownload = () => {
    // Find the canvas rendered by qrcode.react
    const canvas = document.querySelector('#qr-canvas-container canvas');
    if (!canvas) return;
    const url = canvas.toDataURL('image/png');
    const link = document.createElement('a');
    link.download = `fundit-qr-${Date.now()}.png`;
    link.href = url;
    link.click();
  };

  const handleWhatsApp = () => {
    const text = encodeURIComponent(`💙 Support "${campaignTitle}" on FundIt: ${campaignUrl}`);
    window.open(`https://wa.me/?text=${text}`, '_blank', 'noopener,noreferrer');
    if (onShare) onShare();
  };

  return (
    <div className="qr-overlay" id="qr-modal-overlay" onClick={(e) => { if (e.target === e.currentTarget) onClose(); }} role="dialog" aria-modal="true" aria-label="QR Code Modal">
      <div className="qr-modal" id="qr-modal">
        <div className="qr-modal-header">
          <h3>📱 Scan & Share</h3>
          <button className="qr-close-btn" onClick={onClose} aria-label="Close QR modal" id="btn-qr-close">✕</button>
        </div>

        <div className="qr-modal-body">
          <p className="qr-subtitle">Scan this QR code to open the campaign on any device</p>

          <div id="qr-canvas-container" className="qr-canvas-wrapper" ref={canvasRef}>
            <QRCode
              value={campaignUrl}
              size={220}
              level="H"
              includeMargin={true}
              bgColor="#ffffff"
              fgColor="#1a56db"
            />
          </div>

          <p className="qr-url-text">{campaignUrl}</p>

          <div className="qr-actions">
            <button
              className="qr-btn qr-btn-download"
              id="btn-qr-download"
              onClick={handleDownload}
            >
              ⬇️ Download PNG
            </button>
            <button
              className="qr-btn qr-btn-wa"
              id="btn-qr-whatsapp"
              onClick={handleWhatsApp}
            >
              📱 Share on WhatsApp
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default QRCodeModal;
